let nextAttachmentId = 4474;

export function listTicketAttachments(session: Session, ticketId: number) {
  const rows = attachmentsForTicket(ticketId).map((a) => ({
    id: a.id,
    filename: a.filename,
    contentType: a.contentType,
  }));
  return { status: 200, body: rows };
}

export function attachmentsForTicket(ticketId: number): Attachment[] {
  return attachments.filter((a) => a.ticketId === ticketId);
}

export function uploadAttachment(
  session: Session,
  ticketId: number,
  filename: string,
  contentType: string,
  data: string,
) {
  const row = insertAttachment(ticketId, session.userId, filename, contentType, data);
  return { status: 201, body: { id: row.id, filename: row.filename } };
}

export function insertAttachment(
  ticketId: number,
  uploadedBy: string,
  filename: string,
  contentType: string,
  data: string,
): Attachment {
  const row = { id: nextAttachmentId++, ticketId, uploadedBy, filename, contentType, data };
  attachments.push(row);
  return row;
}

